import base64
import zlib
import requests
from urllib.parse import quote_plus
from datetime import datetime
import uuid

def build_saml_request(destination_url, user_info):
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    request_id = '_' + str(uuid.uuid4())
    
    saml_request_template = f"""
    <samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" 
                        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                        ID="{request_id}" 
                        Version="2.0" 
                        IssueInstant="{issue_instant}" 
                        Destination="{destination_url}" 
                        ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST" 
                        AssertionConsumerServiceURL="{user_info['assertion_consumer_service_url']}">
        <saml:Issuer>{user_info['issuer']}</saml:Issuer>
        <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified" AllowCreate="true"/>
    </samlp:AuthnRequest>
    """
    
    def encode_saml_request(saml_request):
        compressed_request = zlib.compress(saml_request.encode('utf-8'))[2:-4]
        base64_request = base64.b64encode(compressed_request)
        return quote_plus(base64_request)

    encoded_request = encode_saml_request(saml_request_template)
    response = requests.post(destination_url, data={'SAMLRequest': encoded_request})
    return response

